import express from 'express';
import path from 'path';
import { fileURLToPath } from 'url';
import Database from 'better-sqlite3';
import { createServer as createViteServer } from 'vite';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

// Initialize SQLite database
const db = new Database('cms.db');

// Ensure tables exist
db.exec(`
  CREATE TABLE IF NOT EXISTS cms_data (
    key TEXT PRIMARY KEY,
    value TEXT
  );
  CREATE TABLE IF NOT EXISTS cms_media (
    key TEXT PRIMARY KEY,
    value TEXT
  );
`);

async function startServer() {
  const app = express();
  const PORT = 3000;

  // Increase body size limit for high-resolution Base64 uploads
  app.use(express.json({ limit: '50mb' }));
  app.use(express.urlencoded({ limit: '50mb', extended: true }));

  // API Endpoints
  // 1. Fetch all CMS configuration keys
  app.get('/api/cms/all', (req, res) => {
    try {
      const stmt = db.prepare('SELECT key, value FROM cms_data');
      const rows = stmt.all() as { key: string; value: string }[];
      const data: Record<string, string> = {};
      rows.forEach(row => {
        data[row.key] = row.value;
      });
      res.json({ success: true, data });
    } catch (error: any) {
      res.status(500).json({ success: false, error: error.message });
    }
  });

  // 2. Batch update/insert multiple CMS keys (autosave & save changes)
  app.post('/api/cms/batch', (req, res) => {
    try {
      const payload = req.body;
      const insert = db.prepare('INSERT OR REPLACE INTO cms_data (key, value) VALUES (?, ?)');
      
      const transaction = db.transaction((dataObj: Record<string, string>) => {
        for (const [key, val] of Object.entries(dataObj)) {
          insert.run(key, typeof val === 'object' ? JSON.stringify(val) : String(val));
        }
      });
      
      transaction(payload);
      res.json({ success: true });
    } catch (error: any) {
      res.status(500).json({ success: false, error: error.message });
    }
  });

  // 3. Fetch specific uploaded media item (Base64 data)
  app.get('/api/media/:key', (req, res) => {
    try {
      const { key } = req.params;
      const stmt = db.prepare('SELECT value FROM cms_media WHERE key = ?');
      const row = stmt.get(key) as { value: string } | undefined;
      if (row) {
        res.json({ success: true, value: row.value });
      } else {
        res.status(404).json({ success: false, message: 'Media not found' });
      }
    } catch (error: any) {
      res.status(500).json({ success: false, error: error.message });
    }
  });

  // 4. Save/Upload a media item
  app.post('/api/media', (req, res) => {
    try {
      const { key, value } = req.body;
      if (!key || !value) {
        res.status(400).json({ success: false, message: 'Key and value are required' });
        return;
      }
      const stmt = db.prepare('INSERT OR REPLACE INTO cms_media (key, value) VALUES (?, ?)');
      stmt.run(key, value);
      res.json({ success: true });
    } catch (error: any) {
      res.status(500).json({ success: false, error: error.message });
    }
  });

  // 5. Delete a specific CMS key (factory reset)
  app.post('/api/cms/delete/:key', (req, res) => {
    try {
      const { key } = req.params;
      const stmt = db.prepare('DELETE FROM cms_data WHERE key = ?');
      stmt.run(key);
      res.json({ success: true });
    } catch (error: any) {
      res.status(500).json({ success: false, error: error.message });
    }
  });

  // Serve Frontend
  if (process.env.NODE_ENV !== 'production') {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: 'spa',
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res, next) => {
      if (req.path.startsWith('/api/')) {
        return next();
      }
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, '0.0.0.0', () => {
    console.log(`[Server] Running on http://0.0.0.0:${PORT} in ${process.env.NODE_ENV || 'development'} mode`);
  });
}

startServer().catch(err => {
  console.error('[Server] Startup failed:', err);
});
